import React, {useEffect} from 'react';
import {AuthorizationCode} from "react-native-app-auth";
import * as Keychain from "react-native-keychain";

const config = {
  issuer: 'https://your.issuer', // Your Auth0 domain
  clientId: 'client-id',  // Your Auth0 Client ID
  redirectUrl: 'com.yourapp:/callback',   // Redirect URL for your app (must be set in the Authorization tab of your Auth0 application settings)
  scopes: ['openid', 'profile'],  // The requested scopes
};

const authorizationCode = new AuthorizationCode(config);

export default function App() {
  useEffect(() => {
    const setupAuth = async () => {
      try {
        const authSession = await authorizationCode.authorize();

        if (authSession && authSession.accessToken) {
          // save your tokens in keychain or any secure storage 
          Keychain.setGenericPassword('user', JSON.stringify(authSession));
        } else {
           console.log("Cancelled by user");
        }
      } catch (err) {
         console.error(err);
      }
    };
    
    setupAuth();
  }, []);
  
  return (
    <View>
      <Text>Logging in...</Text>
    </View>
  );
}